// Filter out the no-op {success: true} row that n8n Postgres returns when
// UPDATE ... RETURNING finds no matching rows. Only pass through items that
// have a numeric 'id' field (a real outreach_item row).
const items = $input.all();
const valid = items.filter(i => i.json && i.json.id != null && String(i.json.id).match(/^\d+$/));
if (valid.length === 0) {
  return [];
}
return valid;

const item = $input.item.json;
const sourcePlatform = item.source_platform || '';
const sourceUrl = item.source_url || '';
const sourceAuthor = item.source_author || 'unknown';
const sourceCommunity = item.source_community || 'unknown';
const sourceExcerpt = item.source_excerpt || '';

const promptText = `You are drafting outreach as the founder of PlotLens. PlotLens is narrative intelligence for fiction writers: it extracts story canon (characters, locations, timelines, rules) and validates continuity across a manuscript. **It does not generate prose.**

## Source context

- Platform: ${sourcePlatform}
- URL: ${sourceUrl}
- Author / community: ${sourceAuthor} / ${sourceCommunity}
- Excerpt:
  > ${sourceExcerpt}

## Voice rules

- Calm, practical, writer-friendly. No hype. No "AI slop."
- Avoid developer jargon: entities, validation rules, embeddings, canonical graph.
- Prefer writer language: characters, story bible, continuity, source passage, manuscript.
- Never claim PlotLens writes prose.
- Never invent features, launch dates, metrics, integrations, prices, or customer counts.

## Channel rules

- For Reddit: no sales CTA unless the post directly asks for tools.
- For replies: answer the person's actual problem before mentioning anything we built.
- For X/Bluesky/Mastodon original posts: stand-alone, useful even if no one clicks through.

## Output

Return JSON with exactly these fields:

\`\`\`json
{
  "should_reply": true,
  "recommended_destination": "reddit_reply",
  "manual_only": false,
  "drafts": [
    {
      "variant": "helpful_only",
      "draft_text": "...",
      "risk_flags": ["e.g. mentions_pricing", "..."]
    },
    {
      "variant": "founder_context",
      "draft_text": "...",
      "risk_flags": []
    },
    {
      "variant": "soft_product",
      "draft_text": "...",
      "risk_flags": []
    }
  ]
}
\`\`\`

Allowed values:
- \`should_reply\`: \`true\` or \`false\`
- \`recommended_destination\`: one of \`reddit_reply\`, \`reddit_post\`, \`x_post\`, \`x_reply\`, \`bluesky_post\`, \`mastodon_post\`, \`linkedin_post\`, \`newsletter\`
- \`manual_only\`: \`true\` or \`false\`
- One entry per \`variant\` key. Always return all three.
- \`risk_flags\` is a list of short strings naming any concern (mentions pricing, makes a claim about features, refers to a competitor, etc.). Empty list if clean.

Return only the JSON, no surrounding prose.`;

return [{ json: { outreach_item_id: item.id, source_platform: sourcePlatform, source_url: sourceUrl, source_author: sourceAuthor, source_community: sourceCommunity, source_excerpt: sourceExcerpt, prompt: promptText } }];

const response = $input.item.json;

// The Anthropic node with simplify:false returns the full API response.
// Retrieve the original outreach_item_id from the Build Prompt upstream node
// using n8n paired item tracking.
const originalItem = $('Build Prompt').item.json;
const outreachItemId = originalItem.outreach_item_id;

if (!outreachItemId) {
  throw new Error('Could not find outreach_item_id from Build Prompt. originalItem=' + JSON.stringify(originalItem));
}

let rawText;
try {
  rawText = response.content[0].text;
} catch(e) {
  throw new Error('Anthropic response missing content[0].text: ' + JSON.stringify(response));
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch(e) {
  const stripped = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  try {
    parsed = JSON.parse(stripped);
  } catch(e2) {
    throw new Error('Failed to parse Anthropic JSON response: ' + rawText.slice(0, 500));
  }
}

if (!Array.isArray(parsed.drafts) || parsed.drafts.length !== 3) {
  throw new Error('Expected drafts array of length 3, got: ' + JSON.stringify(parsed.drafts));
}
for (const d of parsed.drafts) {
  if (!d.variant || !d.draft_text) {
    throw new Error('Draft missing variant or draft_text: ' + JSON.stringify(d));
  }
}

return [{ json: {
  outreach_item_id: outreachItemId,
  should_reply: parsed.should_reply,
  recommended_destination: parsed.recommended_destination,
  manual_only: parsed.manual_only,
  drafts: parsed.drafts
} }];

const item = $input.item.json;
const drafts = item.drafts;

return drafts.map(draft => ({
  json: {
    outreach_item_id: item.outreach_item_id,
    recommended_destination: item.recommended_destination,
    manual_only: item.manual_only,
    variant: draft.variant,
    draft_text: draft.draft_text,
    risk_flags: draft.risk_flags || []
  }
}));

// Collect all 3 variant items and build ONE combined risk-check prompt.
// Runs once with all items — avoids the n8n v1 per-item LangChain node limitation
// (LangChain nodes only process item[0] in this n8n version).
const allItems = $input.all();
const sourceExcerpt = $('Build Prompt').item.json.source_excerpt || '';

const draftsSummary = allItems.map((itm, idx) => {
  const d = itm.json;
  return `### Draft ${idx + 1}: variant="${d.variant || ''}"
Platform: ${d.recommended_destination || ''}
Text:
> ${d.draft_text || ''}`;
}).join('\n\n');

const promptText = `You are reviewing outreach drafts for the PlotLens founder. Score each draft on a 0-100 risk scale.

- **0-20**: Safe to auto-quick-approve. No claims about features that don't exist, no pricing, no competitor mentions, no controversial takes, no apology-style replies, no spam patterns.
- **21-50**: Needs human review but probably fine.
- **51-100**: Flag for careful review. Examples: mentions specific roadmap features, makes a quantitative product claim, replies to a sensitive topic (mental health, harassment, AI ethics debate), uses absolute language ("always", "best", "only").

${draftsSummary}

## Source context

> ${sourceExcerpt}

## Output

Return JSON with exactly 3 entries, one per draft in order:

\`\`\`json
[
  {"variant": "helpful_only", "risk_score": 0, "reasons": ["..."]},
  {"variant": "founder_context", "risk_score": 0, "reasons": ["..."]},
  {"variant": "soft_product", "risk_score": 0, "reasons": ["..."]}
]
\`\`\`

Only return the JSON array. No prose around it.`;

return [{ json: {
  _all_variants: allItems.map(i => i.json),
  risk_check_prompt: promptText
} }];

// Apply Haiku risk scores to all 3 variant items, compute SHA-256 content hashes,
// and pack everything into one item for a single batch Postgres INSERT.
// This pattern avoids n8n multi-item propagation issues beyond a LangChain node.

function sha256(str) {
  const bytes = [];
  for (let i = 0; i < str.length; i++) {
    let c = str.charCodeAt(i);
    if (c < 0x80) { bytes.push(c); }
    else if (c < 0x800) { bytes.push(0xC0|(c>>6), 0x80|(c&0x3F)); }
    else if (c < 0xD800 || c >= 0xE000) { bytes.push(0xE0|(c>>12), 0x80|((c>>6)&0x3F), 0x80|(c&0x3F)); }
    else { i++; c=0x10000+(((c&0x3FF)<<10)|(str.charCodeAt(i)&0x3FF)); bytes.push(0xF0|(c>>18),0x80|((c>>12)&0x3F),0x80|((c>>6)&0x3F),0x80|(c&0x3F)); }
  }
  const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const msgLen=bytes.length; bytes.push(0x80);
  while((bytes.length%64)!==56) bytes.push(0);
  const bitLen=msgLen*8; bytes.push(0,0,0,0,(bitLen>>>24)&0xFF,(bitLen>>>16)&0xFF,(bitLen>>>8)&0xFF,bitLen&0xFF);
  function rotr(x,n){return(x>>>n)|(x<<(32-n));}
  function ch(x,y,z){return(x&y)^(~x&z);}
  function maj(x,y,z){return(x&y)^(x&z)^(y&z);}
  function sig0(x){return rotr(x,2)^rotr(x,13)^rotr(x,22);}
  function sig1(x){return rotr(x,6)^rotr(x,11)^rotr(x,25);}
  function gam0(x){return rotr(x,7)^rotr(x,18)^(x>>>3);}
  function gam1(x){return rotr(x,17)^rotr(x,19)^(x>>>10);}
  for(let offset=0;offset<bytes.length;offset+=64){
    const w=new Array(64);
    for(let i=0;i<16;i++) w[i]=((bytes[offset+i*4]<<24)|(bytes[offset+i*4+1]<<16)|(bytes[offset+i*4+2]<<8)|bytes[offset+i*4+3])>>>0;
    for(let i=16;i<64;i++) w[i]=(gam1(w[i-2])+w[i-7]+gam0(w[i-15])+w[i-16])>>>0;
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let i=0;i<64;i++){const t1=(h+sig1(e)+ch(e,f,g)+K[i]+w[i])>>>0;const t2=(sig0(a)+maj(a,b,c))>>>0;h=g;g=f;f=e;e=(d+t1)>>>0;d=c;c=b;b=a;a=(t1+t2)>>>0;}
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  function hex(n){return('00000000'+(n>>>0).toString(16)).slice(-8);}
  return hex(h0)+hex(h1)+hex(h2)+hex(h3)+hex(h4)+hex(h5)+hex(h6)+hex(h7);
}

const haikusResponse = $input.item.json;
const variantsData = $('Build Risk Prompt').item.json._all_variants;

// Parse Haiku risk scores
let rawText;
try { rawText = haikusResponse.content[0].text; } catch(e) { rawText = null; }

const scoreMap = {};
if (rawText) {
  let parsed;
  try { parsed = JSON.parse(rawText); } catch(e) {
    const stripped = rawText.replace(/^```json\s*/i,'').replace(/```\s*$/i,'').trim();
    try { parsed = JSON.parse(stripped); } catch(e2) { parsed = null; }
  }
  if (Array.isArray(parsed)) {
    for (const entry of parsed) {
      const risk = entry.risk_score;
      if (entry.variant && typeof risk === 'number' && risk >= 0 && risk <= 100) {
        scoreMap[entry.variant] = risk;
      }
    }
  }
}

// Build enriched rows with risk scores + content hashes
const rows = variantsData.map(v => {
  const risk = scoreMap[v.variant];
  const riskScore = (typeof risk === 'number') ? risk : 75;
  const destination = v.recommended_destination || '';
  const postType = v.suggested_post_type || destination.split('_')[1] || 'post';
  const hash = sha256((v.draft_text || '') + destination + postType);
  let riskFlags = v.risk_flags;
  if (!Array.isArray(riskFlags)) { try { riskFlags = JSON.parse(riskFlags); } catch(e) { riskFlags = []; } }
  if (!Array.isArray(riskFlags)) riskFlags = [];
  return {
    outreach_item_id: v.outreach_item_id,
    variant: v.variant,
    draft_text: v.draft_text || '',
    recommended_destination: destination,
    suggested_post_type: postType,
    risk_flags_json: JSON.stringify(riskFlags.map(f => String(f))),
    risk_score: riskScore,
    manual_only: v.manual_only,
    content_hash: hash
  };
});

return [{ json: { rows } }];
